import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generator'

export function onManifest(): GeneratorManifest {
  return {
    prettyName: 'Prisma REST Client',
    defaultOutput: './generated/rest-client',
  }
}

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output?.value
  if (!output) {
    throw new Error('No output directory specified for generator-rest-client')
  }

  const code = generateRestClient(options.dmmf)

  await fs.promises.mkdir(output, { recursive: true })
  await fs.promises.writeFile(path.join(output, 'rest-client.ts'), code, 'utf-8')
}

