/**
 * Indent every line in a block of text by the given number of spaces.
 */
export function indent(text: string, spaces: number): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : pad + line))
    .join('\n')
}

/**
 * Convert a Prisma scalar type to the corresponding TypeScript type.
 */
export function prismaTypeToTs(type: string): string {
  switch (type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Buffer'
    default:
      return type
  }
}

/**
 * Produce a TypeScript property declaration for a single DMMF field.
 */
export function fieldToProperty(field: { name: string; type: string; isList: boolean; isRequired: boolean }): string {
  let tsType = prismaTypeToTs(field.type)
  if (field.isList) {
    tsType = `${tsType}[]`
  }
  const optional = field.isRequired ? '' : '?'
  return `${field.name}${optional}: ${tsType}`
}

