import type * as DMMF from '@prisma/dmmf'

import { fieldToProperty, indent } from './template'

/**
 * Generate a complete typed REST API client from a DMMF document.
 * Produces a single self-contained TypeScript module with interfaces
 * and CRUD methods for every model in the schema.
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models
  const sections: string[] = [generateHeader()]

  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
  }

  sections.push(generateWhereUniqueInput())
  sections.push(generateRestClientClass(models))

  return sections.join('\n\n') + '\n'
}

function generateHeader(): string {
  return [
    '// -----------------------------------------------',
    '// REST Client generated by @prisma/generator-rest-client',
    '// Do not edit manually.',
    '// -----------------------------------------------',
    '',
    'type RequestInit = globalThis.RequestInit',
  ].join('\n')
}

/** Emit a TypeScript interface mirroring all scalar fields of a model. */
function generateModelInterface(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const props = scalarFields.map((f) => fieldToProperty(f)).join('\n')

  return [`export interface ${model.name} {`, indent(props, 2), '}'].join('\n')
}

/** Emit a creation input type — all scalar fields except auto-generated ones. */
function generateCreateInput(model: DMMF.Model): string {
  const writableFields = model.fields.filter(
    (f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isGenerated && !f.isReadOnly && !f.isUpdatedAt,
  )

  const props = writableFields
    .map((f) => {
      const isOptional = !f.isRequired || f.hasDefaultValue || f.isId
      return fieldToProperty({ ...f, isRequired: !isOptional })
    })
    .join('\n')

  return [`export interface ${model.name}CreateInput {`, indent(props, 2), '}'].join('\n')
}

/** Emit an update input type — all writable scalar fields made optional. */
function generateUpdateInput(model: DMMF.Model): string {
  const writableFields = model.fields.filter(
    (f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isGenerated && !f.isReadOnly,
  )

  const props = writableFields.map((f) => fieldToProperty({ ...f, isRequired: false })).join('\n')

  return [`export interface ${model.name}UpdateInput {`, indent(props, 2), '}'].join('\n')
}

function generateWhereUniqueInput(): string {
  return [
    '/** Generic unique-identifier lookup. Pass the ID field value as a key. */',
    'export type WhereUniqueInput = Record<string, string | number | bigint>',
  ].join('\n')
}

function generateRestClientClass(models: readonly DMMF.Model[]): string {
  const methods = models.map((m) => generateModelMethods(m)).join('\n\n')

  return [
    'export class RestClient {',
    '  #baseUrl: string',
    '  #defaultHeaders: Record<string, string>',
    '',
    '  constructor(baseUrl: string, defaultHeaders: Record<string, string> = {}) {',
    '    this.#baseUrl = baseUrl.replace(/\\/$/, "")',
    '    this.#defaultHeaders = {',
    "      'Content-Type': 'application/json',",
    '      ...defaultHeaders,',
    '    }',
    '  }',
    '',
    '  async #request<T>(path: string, init?: RequestInit): Promise<T> {',
    '    const response = await fetch(`${this.#baseUrl}${path}`, {',
    '      ...init,',
    '      headers: {',
    '        ...this.#defaultHeaders,',
    '        ...(init?.headers as Record<string, string> | undefined),',
    '      },',
    '    })',
    '',
    '    if (!response.ok) {',
    '      throw new Error(`REST request failed: ${response.status} ${response.statusText}`)',
    '    }',
    '',
    '    return response.json() as Promise<T>',
    '  }',
    '',
    methods,
    '}',
  ].join('\n')
}

function generateModelMethods(model: DMMF.Model): string {
  const name = model.name
  const resource = toResourcePath(name)

  return indent(
    [
      `/** Find many ${name} records. */`,
      `async ${lowerFirst(name)}FindMany(): Promise<${name}[]> {`,
      `  return this.#request<${name}[]>('/${resource}')`,
      '}',
      '',
      `/** Find a unique ${name} record by its identifier. */`,
      `async ${lowerFirst(name)}FindUnique(where: WhereUniqueInput): Promise<${name}> {`,
      `  const id = Object.values(where)[0]`,
      `  return this.#request<${name}>(\`/${resource}/\${id}\`)`,
      '}',
      '',
      `/** Create a new ${name} record. */`,
      `async ${lowerFirst(name)}Create(data: ${name}CreateInput): Promise<${name}> {`,
      `  return this.#request<${name}>('/${resource}', {`,
      `    method: 'POST',`,
      `    body: JSON.stringify(data),`,
      `  })`,
      '}',
      '',
      `/** Update an existing ${name} record. */`,
      `async ${lowerFirst(name)}Update(where: WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {`,
      `  const id = Object.values(where)[0]`,
      `  return this.#request<${name}>(\`/${resource}/\${id}\`, {`,
      `    method: 'PATCH',`,
      `    body: JSON.stringify(data),`,
      `  })`,
      '}',
      '',
      `/** Delete a ${name} record. */`,
      `async ${lowerFirst(name)}Delete(where: WhereUniqueInput): Promise<${name}> {`,
      `  const id = Object.values(where)[0]`,
      `  return this.#request<${name}>(\`/${resource}/\${id}\`, {`,
      `    method: 'DELETE',`,
      `  })`,
      '}',
    ].join('\n'),
    2,
  )
}

/** Convert "User" to "users", "BlogPost" to "blog-posts", etc. */
function toResourcePath(name: string): string {
  const kebab = name
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .replace(/([A-Z])([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
  return kebab.endsWith('s') ? kebab : `${kebab}s`
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

